      if (router_ != nullptr) {
        router_gui_->setRouter(router_.get());
      }
    }
    gui::Gui::get()->registerRenderer(router_gui_.get());
  } else {
    gui::Gui::get()->unregisterRenderer(router_gui_.get());
  }
}

